var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>익명의 기업으로부터 수신한 메일입니다.</color>`,JPN:`<color=#ffd34c>匿名の企業から受信したメールです。</color>`,ENG:`<color=#ffd34c>A mail arrived from an anonymous company.</color>`,TWN:`<color=#ffd34c>來自匿名企業的一封郵件。</color>`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`방금 입금을 마쳤으니 확인 바랍니다.`,JPN:`先ほど入金しましたので、ご確認ください。`,ENG:`We just deposited the payment. Please confirm.`,TWN:`就在剛才匯款完畢，請您確認。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`덕분에 무사히 채굴을 완수할 수 있었습니다.`,JPN:`お陰様で無事に採掘を終えることができました。`,ENG:`Thanks to your efforts, we were able to finish mining safely.`,TWN:`多虧您才能順利的完成採掘任務。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`변종들이야 그렇다 쳐도 그 여자괴물, 되살아난 좀비치곤 힘이 어마무시하더군요.`,JPN:`変種はともかく、あの女の怪物は……蘇ったゾンビにしては物凄い力でした。`,ENG:`I can understand the mutants, but that female monster was really strong for a reanimated zombie.`,TWN:`變種就不用說了，那個女怪物以復活的僵屍來說，力氣未免也太大了吧。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`여러분의 도움이 없었더라면 탈출은 꿈도 못 꿨을 겁니다.`,JPN:`皆さんのご協力が無ければ、脱出など夢のまた夢だったでしょう。`,ENG:`We wouldn't have been able to even dream of escaping without your help.`,TWN:`要是沒有您的幫助，我們做夢都沒想到能夠逃離那裡。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`다음에 만나면 제가 술 한 잔 사겠습니다.`,JPN:`今度お会いした時には、是非一杯奢らせてください。`,ENG:`Allow me to buy you a drink next time we meet.`,TWN:`下次見面的話我請客吧。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};